// Mock dependencies
const EventEmitter3 = require('eventemitter3');

// Mock classes
class MockGameState extends EventEmitter3 {
  constructor() {
    super();
    this.players = [];
    this.tokens = [];
    this.board = null;
    this.currentPlayer = null;
    this.currentRound = 0;
    this.maxRounds = 15;
  }
}

class MockBoard {
  constructor() {
    this.tiles = new Map(); // tileId -> { type, element, isSafeZone }
  }

  getTile(tileId) {
    return this.tiles.get(tileId);
  }

  isSafeZone(tileId) {
    const tile = this.tiles.get(tileId);
    return tile && tile.isSafeZone;
  }

  getNextTile(currentTileId, direction = 'clockwise') {
    // Simplified: return next tile ID based on board topology
    // Real implementation would use path maps
    return (currentTileId + 1) % 61;
  }

  getNearestSafeZoneBehind(targetTileId, playerId) {
    // Simplified: search backwards along path until Safe Zone found
    let id = targetTileId - 1;
    while (id >= 0) {
      if (this.isSafeZone(id)) return id;
      id--;
    }
    return 0; // fallback
  }
}

class MockToken {
  constructor({ id, ownerId, startingTile }) {
    this.id = id;
    this.ownerId = ownerId;
    this.tileId = startingTile;
    this.atk = 0;
    this.frozenRounds = 0;
  }

  isFrozen() {
    return this.frozenRounds > 0;
  }

  moveTo(tileId) {
    this.tileId = tileId;
  }
}

class MockPlayer {
  constructor({ id, character }) {
    this.id = id;
    this.character = character; // { affinity, atk: 30, mag: 10, hp: 1000 }
    this.hp = character.hp;
    this.mag = 0;
    this.elementQueue = []; // array of element types
    this.magCap = 100;
    this.maxElementQueue = 7;
    this.emptyTileVisits = 0;
    this.comboCount = 0;
    this.consecutiveRollsThisTurn = 0;
    this.doubleRollCooldown = 0;
    this.ultimateExtraRolls = 0;
    this.artifactsUnlocked = {
      swap: false,
      change: false,
      charge: false
    };
    this.artifactLevel = 3; // slots
    this.tokens = [];
  }

  canSelectToken() {
    return this.tokens.some(t => !t.isFrozen());
  }

  addElement(element) {
    // If full, remove oldest (head)
    if (this.elementQueue.length >= this.maxElementQueue) {
      this.elementQueue.shift();
    }
    this.elementQueue.push(element);
    // Check combos
    this.evaluateCombos();
  }

  evaluateCombos() {
    // C3: 3 identical in a row
    // C4: 4 distinct in a row
    // Priority: C3 first
    let i = 0;
    while (i < this.elementQueue.length - 2) {
      const slice3 = this.elementQueue.slice(i, i + 3);
      if (slice3[0] === slice3[1] && slice3[1] === slice3[2]) {
        // C3 triggers
        this.elementQueue.splice(i, 3);
        this.applyComboReward(1);
        this.comboCount++;
        i = 0; // rescan from start
        continue;
      }
      i++;
    }

    // Check C4
    i = 0;
    while (i < this.elementQueue.length - 3) {
      const slice4 = this.elementQueue.slice(i, i + 4);
      const distinct = new Set(slice4).size === 4;
      if (distinct) {
        this.elementQueue.splice(i, 4);
        this.applyComboReward(1);
        this.comboCount++;
        i = 0;
        continue;
      }
      i++;
    }
  }

  applyComboReward(milestone) {
    // Tier 1: +150 ATK to all tokens
    let atkBonus = 0;
    let multiplier = 1;
    let atkMult = 1;

    if (milestone >= 1) {
      atkBonus = 150;
    }
    if (milestone >= 2) {
      multiplier = 2; // tileGainMultiplier
    }
    if (milestone >= 3) {
      atkMult = 1.5;
    }

    this.tokens.forEach(t => {
      t.atk = Math.floor(t.atk * atkMult) + atkBonus;
    });

    // Store state for later checks
    this._lastReward = { atkBonus, multiplier, atkMult };
  }

  gainMAG(amount) {
    const effective = amount * (this._lastReward?.multiplier || 1);
    this.mag = Math.min(this.mag + effective, this.magCap);
  }

  canUseUltimate() {
    return this.mag >= 50 && this.consecutiveRollsThisTurn < 3;
  }

  useUltimate() {
    if (!this.canUseUltimate()) return false;
    this.mag -= 50;
    this.ultimateExtraRolls++;
    return true;
  }

  incrementConsecutiveRolls() {
    this.consecutiveRollsThisTurn++;
  }

  resetTurnRollCounters() {
    this.consecutiveRollsThisTurn = 0;
  }

  unlockArtifact(type) {
    this.artifactsUnlocked[type] = true;
  }
}

// Helper to create test context
function createTestContext() {
  const state = new MockGameState();
  const board = new MockBoard();
  const player1 = new MockPlayer({
    id: 'p1',
    character: { affinity: 'Fire', atk: 30, mag: 10, hp: 1000 }
  });
  const player2 = new MockPlayer({
    id: 'p2',
    character: { affinity: 'Ice', atk: 30, mag: 10, hp: 1000 }
  });
  state.players = [player1, player2];
  state.board = board;

  // Create tokens for each player (3 each)
  for (let i = 0; i < 3; i++) {
    const t1 = new MockToken({ id: `p1_t${i}`, ownerId: 'p1', startingTile: 51 + i });
    const t2 = new MockToken({ id: `p2_t${i}`, ownerId: 'p2', startingTile: 0 + i });
    player1.tokens.push(t1);
    player2.tokens.push(t2);
    state.tokens.push(t1, t2);
  }

  return { state, board, player1, player2 };
}

