describe('Elemental Hunter — Edge Cases', () => {

  test('Two tokens from same player landing on same tile in same turn process independently', () => {
    const { player1, board } = createTestContext();
    const tokenA = player1.tokens[0];
    const tokenB = player1.tokens[1];
    tokenA.tileId = 5;
    tokenB.tileId = 5;

    // Both should be allowed to occupy same tile? GDD doesn't forbid same-team stacking
    expect(tokenA.tileId).toBe(tokenB.tileId);
  });

  test('Two tokens from different players on same non-Safe Zone: Kick triggers for each landing', () => {
    // The order matters: whichever lands first becomes target for second?
    // GDD: Kick when landing on opponent tile. Both tokens land in same turn?
    // Assume sequential resolution; last to land kicks the already-present opponent.
    const { player1, player2 } = createTestContext();
    const p1Token = player1.tokens[0];
    const p2Token = player2.tokens[0];
    p1Token.tileId = 5;
    p2Token.tileId = 5; // p2 lands after p1

    // If p2 lands on p1's tile, p1 gets kicked
    expect(p1Token.tileId).toBe(5);
    expect(p2Token.tileId).toBe(5);
    // Need full resolution engine to verify kick outcome
  });

  test('Token already on Final Goal: no effect if visited again', () => {
    const { player1 } = createTestContext();
    const token = player1.tokens[0];
    token.tileId = 31; // Final Goal for P1

    const firstVisit = () => {
      token.hasScoredGoal = true;
    };
    firstVisit();
    expect(token.hasScoredGoal).toBe(true);

    // Second visit should not double-score
    const secondVisit = () => {
      // check flag
    };
    secondVisit();
    expect(token.hasScoredGoal).toBe(true);
  });

  test('Artifact selection persists: unlocked artifacts remain available for future visits', () => {
    const { player1 } = createTestContext();
    player1.emptyTileVisits = 2;
    if (player1.emptyTileVisits >= 1) player1.unlockArtifact('swap');
    if (player1.emptyTileVisits >= 2) player1.unlockArtifact('change');
    // On next visit, both should be available
    expect(player1.artifactsUnlocked.swap).toBe(true);
    expect(player1.artifactsUnlocked.change).toBe(true);
  });

  test('If multiple artifacts unlocked, player can choose any available', () => {
    const { player1 } = createTestContext();
    player1.emptyTileVisits = 3;
    if (player1.emptyTileVisits >= 1) player1.unlockArtifact('swap');
    if (player1.emptyTileVisits >= 2) player1.unlockArtifact('change');
    if (player1.emptyTileVisits >= 3) player1.unlockArtifact('charge');

    const available = Object.entries(player1.artifactsUnlocked)
      .filter(([, v]) => v).map(([k]) => k);

    expect(available).toContain('swap');
    expect(available).toContain('change');
    expect(available).toContain('charge');
    expect(available.length).toBe(3);
  });

  test('Consecutive roll cap prevents extra rolls beyond 3 (including Ultimate)', () => {
    const { state } = createTestContext();
    const player = state.players[0];
    player.consecutiveRollsThisTurn = 3;

    expect(player.canUseUltimate()).toBe(false);
  });

  test('Double Roll cooldown decrements per round', () => {
    const { player1 } = createTestContext();
    player1.doubleRollCooldown = 2;

    // Simulate end of round
    player1.doubleRollCooldown--;
    expect(player1.doubleRollCooldown).toBe(1);

    player1.doubleRollCooldown--;
    expect(player1.doubleRollCooldown).toBe(0);
  });

  test('Ultimate Extra Roll increments consecutiveRollsThisTurn', () => {
    const { player1 } = createTestContext();
    player1.mag = 60;
    player1.consecutiveRollsThisTurn = 1;

    const success = player1.useUltimate();
    expect(success).toBe(true);
    expect(player1.ultimateExtraRolls).toBe(1);
    // After using Ultimate, player gets an extra roll turn
    // When that roll turn starts, consecutiveRollsThisTurn will increment
    player1.incrementConsecutiveRolls();
    expect(player1.consecutiveRollsThisTurn).toBe(2);
  });

});

// ==================== Win Conditions ====================

describe('Elemental Hunter — Win/Lose Conditions', () => {

  test('KO: When player HP ≤ 0, opponent wins immediately', () => {
    const { player1, player2 } = createTestContext();
    player2.hp = -10;

    const winner = player2.hp > 0 ? player2 : player1;
    expect(winner.id).toBe('player1');
    expect(player2.hp <= 0).toBe(true);
  });

  test('Round limit: When currentRound = maxRounds, player with higher HP wins', () => {
    const { player1, player2, state } = createTestContext();
    state.currentRound = state.maxRounds;
    player1.hp = 900;
    player2.hp = 850;

    let winner;
    if (state.currentRound >= state.maxRounds) {
      winner = player1.hp > player2.hp ? player1 : player2;
    }
    expect(winner.id).toBe('player1');
  });

  test('Tie-break: HP equal at round limit → Player2 wins', () => {
    const { player1, player2, state } = createTestContext();
    state.currentRound = state.maxRounds;
    player1.hp = 800;
    player2.hp = 800;

    let winner;
    if (state.currentRound >= state.maxRounds) {
      winner = player1.hp === player2.hp ? player2 : (player1.hp > player2.hp ? player1 : player2);
    }
    expect(winner.id).toBe('player2');
  });

});

